INSERT INTO `testes_windows` (`id`, `teste_inicial_profissional_responsavel`, `iniciado`, `c_2a_fase_testes_volumetria`, `resultado`, `clientes_utilizam_funcionalidade`, `nome_da_regra`, `configuracao_da_regra`, `executor_da_regra`, `tipo_de_regra`, `protocolo_parceiro`, `resultado_esperado`, `detalhamento_da_execucao_do_teste`, `resultado_obtido_com_1_arquivo_simples`, `resultado_obtido_com_1_arquivo_1gb`, `resultado_obtido_com_100_arquivos`, `resultado_obtido_com_5000_arquivos`, `versao_do_edie`, `build`, `issue`, `criticidade_issue`, `observacoes`) VALUES
(1, NULL, 0, NULL, NULL, 'Correios', 'ESA 001 - RECEBE FTP COM DESCOMPATACAO', 'Excluir na origem / Compactar / Descompactar/MD5', '10.222.31.111', 'Recepção', 'FTP', 'Fazer o recebimento e  descompactação e respeitando a integridades MD5', 'O arquivo trafegou compactado, chegando no destino descompactado, ao finalizar o trafego o arquivo compactado não foi excluido da origem.', 'Não se aplica', NULL, NULL, NULL, 'V_5.5', 2752.0, NULL, NULL, NULL),
(2, NULL, 0, NULL, NULL, 'Correios', 'ESA 002 - ENVIO FTP COM COMPATACAO', 'Excluir na origem / Compactar / Descompactar/MD5', '10.222.31.111', 'Envio', 'FTP', 'Fazer a compactação, enviar e respeitando a integridade MD5', 'O arquivo foi compactado e enviado ao diretório', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', 2752.0, NULL, NULL, NULL),
(4, NULL, 0, NULL, NULL, 'Correios', 'ESA 005 - ENVIA FTP PERCORRENDO SUBPASTAS', 'Excluir na origem / Não compactar / Percorrer subpastas; integridade; MD5/Manter Estrutura de Diretórios', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio FTP percorrendo subpastas', 'O arquivo foi trafegado,chegando no destino porém, só ate a pasta que continha arquivos .', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', 2752.0, NULL, NULL, NULL),
(5, NULL, 0, NULL, NULL, 'Correios', 'ESA 006 - RECEBE FTP PERCORRENDO SUBPASTAS', 'Excluir na origem / Não compactar / Percorrer subpastas/Manter Estrutura de Diretórios', '10.222.31.111', 'Recepção', 'FTP', 'Fazer o recebimento FTP percorrendo subpastas', 'O arquivo foi recebido e entregue no subdiretório', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', 2752.0, NULL, NULL, NULL),
(6, NULL, 0, NULL, NULL, 'Banestes / Correios', 'ESA 007 - ENVIA FTP SOBREPONDO NO DESTINO', 'Excluir na origem / Não compactar / Sobrepor no destino', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio FTP sobrepondo o destino', 'O arquivo foi enviado e entregue no destino sobrepondo o mesmo', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', 2752.0, NULL, NULL, NULL),
(7, NULL, 0, NULL, NULL, 'Correios', 'ESA 008 - RECEBE FTP SOBREPONDO NO DESTINO', 'Excluir na origem / Não compactar / Sobrepor no destino', '10.222.31.111', 'Recepção', 'FTP', 'Fazer o recebimento FTP sobrepondo o destino', 'O arquivo foi entregue no destino porém não sobrepôs o mesmo.', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', 2752.0, NULL, NULL, NULL),
(8, NULL, 0, NULL, NULL, 'Banestes', 'ESA 010 - ENVIA FTP COM MONITORAR', 'Excluir na origem / Não compactar / Monitorar', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio FTP com monitor', 'Funcionalidade foi desabilitada temporariamente, devido a mal funcionamento da mesma. Foi retirado da tela para evitar suporte até solução da mesma.', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, NULL),
(9, NULL, 0, NULL, NULL, 'Outros', 'ESA 011 - ENVIO FTP COM COPIA LOCAL', 'Excluir na origem / Não compactar / Percorrer subpastas/Sobrepor no destino/Cópia local/Manter Estrutura de Cópia / Manter estrutura no Servidor', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio FTP e cópia local', 'O arquivo foi enviado e feito uma cópia no diretório copia local', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', NULL, NULL, NULL, NULL),
(10, NULL, 0, NULL, NULL, 'Banestes / Correios', 'ESA 012 - ENVIO FTP COM RENOMEIO ', 'Excluir na origem / Não compactar/Renomeio aba Parceiros', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio FTP e o renomeio ', 'O arquivo foi entregue com o renomeio no destino,  com sequencial até após a extensão do arquivo', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', NULL, NULL, NULL, NULL),
(11, NULL, 0, NULL, NULL, 'Banestes / Correios', 'ESA 013 - RECEBE FTP COM RENOMEIO', 'Excluir na origem / Não compactar/ Renomeio (Conversão)', '10.222.31.111', 'Recepção', 'FTP', 'Fazer o recebimento FTP e o renomeio ', 'O arquivo foi recebido com o renomeio correto no destino', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.3', NULL, NULL, NULL, NULL),
(12, NULL, 0, NULL, NULL, 'Banestes', 'ESA 014 - ENVIO FTP TRUNCAR NOME DO ARQUIVO', 'Excluir na origem / Não compactar/ Truncar (Parceiro)', '10.222.31.111', 'Envio', 'FTP', 'Fazer o envio do arquivo para o FTP com o nome truncado', 'Esta sendo feito o truncamento de forma correta, obedecendo a configuração da regra, onde foi realizado teste com 1,2 e 8 posições de truncamento, onde todos os arquivos foram  trafegados e retirados os caracteres conforme estabelecido', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, NULL),
(13, NULL, 0, NULL, NULL, 'Banestes', 'ESA 015 - RECEBE FTP TRUNCAR NOME DO ARQUIVO', 'Excluir na origem / Não compactar/Truncar (Parceiro)', '10.222.31.111', 'Recepção', 'FTP', 'Fazer o recebimento FTP truncar nome do arquivo', 'Arquivo foi trafegado e recepcionado com o truncamento correto.', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, NULL),
(16, NULL, 0, NULL, NULL, 'Correios', 'ESA 016 - LITE MOVER COM ERROS', 'Mover com erros, Excluir na Origem', '10.222.31.112', 'Recepção', 'EDIE Lite', 'Fazer o recebimento e mover com erros', 'Foi alterado a senha do usuario parceiro para gerar a exceção ', NULL, NULL, NULL, NULL, 'V_4.11', NULL, NULL, NULL, 'Não envia e não remove com erro. Log informa arquivo excluído da origem com sucesso.'),
(15, NULL, 0, NULL, NULL, 'Correios', 'ESA 016 - LITE MOVER COM ERROS	', 'Mover com erros, Excluir na Origem', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio e mover com erros', 'Foi alterado a senha do usuario parceiro para gerar a exceção ', NULL, NULL, NULL, NULL, 'V_4.11', NULL, NULL, NULL, NULL),
