(23, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 022 - ENVIO LITE PERCORRE SUBPASTAS MANTENDO ESTRUTURA SUBDIRETORIOS', 'Excluir na origem / Não compactar / Percorrer subpastas / Mantem estrutura subdiretórios', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio e percorrer as subpastas e excluir na origem', 'Os arquivos foram enviandos com sucesso', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(24, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 022 - RECEBE LITE PERCORRE SUBPASTAS MANTENDO ESTRUTURA SUBDIRETORIOS', 'Excluir na origem / Não compactar / Percorrer subpastas / Mantem estrutura subdiretórios', '10.222.31.112', 'Recepção', 'EDIE Lite', 'Fazer o recebimento e percorrer as subpastas, mantendo a estrutura dos subdiretórios', 'Os arquivos foram enviandos com sucesso, criando a estrutura de subdiretórios', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(25, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 023 - LITE ENVIA SOBREPONDO NO DESTINO', 'Excluir na origem / Não compactar / Sobrepor no destino', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio sobrepondo no destino', 'Os arquivos foram enviandos com sucesso, sobrepondo o mesmo arquivo com conteúdo diferente no destino ', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
