(27, NULL, 0, NULL, NULL, 'Outros', 'ESA 025 - ENVIO LITE VERSIONAR', 'Excluir na origem / Não Compactar / versionar', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio do arquivo versionado', 'os arquivo foram transmitidos, mas não fez criação deixou o arquivo de versionamento na pasta no drive,', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(28, NULL, 0, NULL, NULL, 'Outros', 'ESA 025 - RECEBE LITE VERSIONAR', 'Excluir na origem / Não Compactar / versionar', '10.222.31.112', 'Recepção', 'EDIE Lite', 'Fazer o recebimento do arquivo versionado', 'os arquivo foram transmitidos, mas não fez criação deixou o arquivo de versionamento na pasta no drive,', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(29, NULL, 0, NULL, NULL, 'Banestes', 'ESA 026 - ENVIO LITE /MONITORAR', 'Excluir na origem, monitorar', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio do arquivo sem a necessidade de agendamento ou execução manual', 'Ao criar ou receber um arquivo em um diretório monitorado por uma regra com a funcionalidade de monitorar, o mesmo deve realizar automáticamente o envio do arquivo sem a necessidade de ter um agendamento ou uma execução manual.', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, NULL),
(30, NULL, 0, NULL, NULL, 'Banestes', 'ESA 026 - RECEBE LITE /MONITORAR', 'Excluir na origem, monitorar', '10.222.31.111', 'Recepção', 'EDIE Lite', 'Fazer o envio do arquivo sem a necessidade de agendamento ou execução manual', 'Ao criar ou receber um arquivo em um diretório monitorado por uma regra com a funcionalidade de monitorar, o mesmo deve realizar automáticamente o envio do arquivo sem a necessidade de ter um agendamento ou uma execução manual.', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, NULL),
(31, NULL, 0, NULL, NULL, 'Correios', 'ESA 027 - ENVIO LITE COM COPIA', 'Excluir na origem / Percorrer subpastas / Sobrepor no Destino / Habilitar copia e manter estrutura', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio do arquivo e uma cópia', 'Os arquivos foram enviandos com sucesso', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(32, NULL, 0, NULL, NULL, 'Correios', 'ESA 027 - RECEBE LITE COM COPIA', 'Excluir na origem / Percorrer subpastas / Sobrepor no Destino / Habilitar copia e manter estrutura', '10.222.31.112', 'Recepção', 'EDIE Lite', 'Fazer o recebimento do arquivo  e uma cópia', 'Não tem a função de cópia no protocolo de recepção', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(33, NULL, 0, NULL, NULL, 'Correios', 'ESA 028 - ENVIO LITE COM RENOMEIO', 'Excluir na origem / Não compactar', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio e renomeio do arquivo', 'Foi utilizado uma máscara de renomeio e inserida na regra de envio, onde os arquivos foram trafegados com sucesso e renomeados.', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(34, NULL, 0, NULL, NULL, 'Correios', 'ESA 028 - ENVIO LITE COM RENOMEIO', 'Excluir na origem / Não compactar', '10.222.31.112', 'Recepção', 'EDIE Lite', 'Fazer o recebimento e renomeio', 'Foi utilizado uma máscara de renomeio e inserida na regra de recebimento, onde os arquivos foram trafegados com sucesso e renomeados.', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(35, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 029 - ENVIO LITE COM INTEGRIDADE MD5', 'Excluir na origem / Não compactar', '10.222.31.111', 'Envio', 'EDIE Lite', 'Fazer o envio com integridade MD5', 'Deve ser feita a verificação do hash do arquivo antes do envio, para isso pode ser utilizado o notepad++ na aba tools MD5, e após conferir o hash do arquivo deve enviar via EDIE e conferir o CRC nos relatórios para conferir se é o mesmo anteriormente gerado.', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, 'Foi utilizado o comando Get-FileHash -Path ".\\arquivo.txt" -Algorithm MD5 |||| com powerhell, antes do envio, após enviar foi comparado o código gerado pelo comando e o CRC no tráfego analíco e foi constatados que ambos são idênticos, garantindo a integridade do arquivo'),
(36, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 029 - ENVIO LITE COM INTEGRIDADE MD5', 'Excluir na origem / Não compactar', '10.222.31.111', 'Recepção', 'EDIE Lite', 'Fazer o recebimento com integridade MD5', 'Deve ser feita a verificação do hash do arquivo antes do envio, para isso pode ser utilizado o notepad++ na aba tools MD5, e após conferir o hash do arquivo deve enviar via EDIE e conferir o CRC nos relatórios para conferir se é o mesmo anteriormente gerado.', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, 'Foi utilizado o comando Get-FileHash -Path ".\\arquivo.txt" -Algorithm MD5 |||| com powerhell, antes do envio, após chegar na pasta de recepção foi comparado o código gerado pelo comando e o CRC no tráfego analíco e foi constatados que ambos são idênticos, garantindo a integridade do arquivo'),
(39, NULL, 0, NULL, NULL, 'Correios', 'ESA 032 - CXA COM MÁSCARA DE EXCLUSÃO', 'Não compactar', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer  o recebimento com máscara de exclusão', 'Deve-se colocar no diretório arquivos válidos e arquivos inválidos que no caso são arquivos com máscara *.txt, e assim somente devem ser trafegados todos os arquivos menos os da máscara de exclusão. O teste deve ser feito nos dois sentidos CXA->Server /Server->CXA', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(40, NULL, 0, NULL, NULL, 'Correios', 'ESA 033 - CXA COM TAMANHO MIN / MAXIMO', 'Não compactar', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento com  tamanho minimo e tamanho máximo', 'Arquivos sendo enviado/recebido conforme tamanho minimo e máximo estabelecido', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(42, NULL, 0, NULL, NULL, 'Correios', 'ESA 037 - CXA PERCORRER SUBPASTAS', 'Percorrer Subpastas', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento e percorrer as subpastas', 'O arquivo foi recebido e percorrido a subpasta', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(44, NULL, 0, NULL, NULL, 'Correios / TSE', 'ESA 039 - CXA SOBREPOR LOCALMENTE', 'Sobrepor Localmente', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento e sobrepor localmente', 'O arquivo foi recebido e sobrepondo no destino', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(45, NULL, 0, NULL, NULL, 'Correios', 'ESA 042 - CXA COM RENOMEIO', 'CXA com renomeio', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento com renomeio', 'O arquivo foi recebido e feito o renomeio', NULL, NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, 'CLIENT CXA > SERVIDOR renomeio funciona normalemnte, SERVIDOR > CLIENT CXA não ocorre o renomeio'),
(47, NULL, 0, NULL, NULL, 'Banestes / Correios', 'ESA 044 - CXA COM COPIA NO CLIENT', 'Percorrer Subpastas', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento e percorrer as subpastas', 'O arquivo foi recebido e percorrido a subpasta', NULL, NULL, NULL, NULL, 'V_5.1', NULL, NULL, NULL, 'Ao executar o client recebo o seguinte erro no log: ERROR - 16/01/2026 08:56:29.630 [10.222.31.112] - 500:  - br.com.esales.edienterprise.rest.response.RegraCaixaViewResponse@1d053a7c\nbr.com.esales.odette.exception.EdiException'),
(48, NULL, 0, NULL, NULL, 'Correios', 'ESA 045 - CXA BUSCA ARQUIVO NA RAIZ', 'CXA Busca arquivo na Raiz', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o recebimento busca arquivo na raiz', 'O arquivo foi recebido na pasta raiz. A regra não irá criar uma pasta de envio, todos os arquivos devem ser colocados no diretório de origem com o nome da regra, e para serem encontrados e enviados pelo EDI, devem possuir uma nomenclatura específica: nome do usuário para o qua foi utilizado o download do CXA seguido de #.', NULL, NULL, NULL, NULL, 'V_4.11', NULL, NULL, NULL, NULL),
(49, NULL, 0, NULL, NULL, 'Correios', 'ESA 046 - CXA COM INTEGRIDADE MD5', 'Percorrer Subpastas', '10.222.31.111', 'Recepção', '@EDIE Lite -CXA', 'Fazer o envio com integridade MD5', 'Deve ser feita a verificação do hash do arquivo antes do envio, para isso pode ser utilizado o notepad++ na aba tools MD5, e após conferir o hash do arquivo deve enviar via EDIE e conferir o CRC nos relatórios para conferir se é o mesmo anteriormente gerado.', 'Efetuado com sucesso', NULL, NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(83, NULL, 0, NULL, NULL, 'Correios', 'ESA 048 - ENVIO FTPS PERCORRENDO SUBPASTA', 'Excluir na Origem / Percorrer subpastas', '10.222.31.112', 'Envio', 'FTPS', 'Fazer o envio  percorrendo as pastas', 'O arquivo foi enviado e percorre as subpastas', 'Efetuado com sucesso', 'Efetuado com sucesso', NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
(50, NULL, 0, NULL, NULL, 'Correios', 'ESA 049 - SFTP COM MASCARA DE EXCLUSAO', 'Excluir na Origem / Máscara positiva / Máscara negativa / Mover para diretorio especifico', '10.222.31.112', 'Envio', 'SSH / SFTP', 'Fazer o envio da máscara positiva e movimentar o arquivo da máscara negativa excluindo todos os arquivos para diretorio', 'O arquivo foi enviado ao diretório e destino', 'Efetuado com sucesso', 'Efetuado com sucesso', 'Efetuado com sucesso', 'Efetuado com sucesso', 'V_5.1', '5.5.1_2973', NULL, NULL, NULL),
(52, NULL, 0, NULL, NULL, 'Correios', 'ESA 050 - SFTP TAMANHO MIN/MAX KB', 'Excluir na Origem', '10.222.31.111', 'Envio', 'SSH / SFTP', 'Fazer o envio com tamanho maximo e minimo ', 'O arquivo foi enviado ao diretório e destino', 'A Realizar', 'A Realizar', NULL, NULL, 'V_5.1', '5.5.1_2973', NULL, NULL, 'não trafega 4GB, e só trafega até 3,5gb se aumentar para 30s nas tentativas'),
(54, NULL, 0, NULL, NULL, 'Correios', 'ESA 051 - SFTP MOVER COM ERROS', 'Mover com erros / Excluir na Origem', '10.222.31.111', 'Envio', 'SSH / SFTP', 'Fazer o envio mover com erros e excluir na origem', 'O arquivo não está sendo enviado para pasta deerro ', NULL, NULL, NULL, NULL, 'V_5.1', '5.5.1_2973', NULL, NULL, 'Não trafega, só joga o arquivo bin p pasta de erro'),
(56, NULL, 0, NULL, NULL, 'Outros', 'ESA 052 - SFTP MOVER ARQ DA MASCARA DE EXCLUSAO', 'Excluir na Origem / Mover arquivos da máscara de exclusão para diretório', '10.222.31.111', 'Envio', 'SSH / SFTP', 'Fazer o envio e mover arquivo com máscara de exclusão', 'O arquivo foi enviado e feita a máscara de exclusão', 'Efetuado com sucesso', 'Efetuado com sucesso', NULL, NULL, 'V_5.2.1', 2667.0, NULL, NULL, NULL),
