-- Banco gerado a partir de Testes_eSales.xlsx
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE DATABASE IF NOT EXISTS `testes_esales` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `testes_esales`;

DROP TABLE IF EXISTS `testes_windows`;
CREATE TABLE `testes_windows` (
  `id_pk` INT AUTO_INCREMENT PRIMARY KEY,
  `id` INT,
  `teste_inicial_profissional_responsavel` VARCHAR(255),
  `iniciado` TINYINT(1),
  `c_2a_fase_testes_volumetria` VARCHAR(255),
  `resultado` VARCHAR(255),
  `clientes_utilizam_funcionalidade` VARCHAR(50),
  `nome_da_regra` VARCHAR(100),
  `configuracao_da_regra` VARCHAR(200),
  `executor_da_regra` VARCHAR(50),
  `tipo_de_regra` VARCHAR(50),
  `protocolo_parceiro` VARCHAR(50),
  `resultado_esperado` VARCHAR(200),
  `detalhamento_da_execucao_do_teste` TEXT,
  `resultado_obtido_com_1_arquivo_simples` VARCHAR(50),
  `resultado_obtido_com_1_arquivo_1gb` VARCHAR(50),
  `resultado_obtido_com_100_arquivos` VARCHAR(50),
  `resultado_obtido_com_5000_arquivos` VARCHAR(50),
  `versao_do_edie` VARCHAR(50),
  `build` VARCHAR(50),
  `issue` VARCHAR(255),
  `criticidade_issue` VARCHAR(255),
  `observacoes` TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `testes_linux`;
CREATE TABLE `testes_linux` (
  `id_pk` INT AUTO_INCREMENT PRIMARY KEY,
  `id` INT,
  `teste_inicial_profissional_responsavel` VARCHAR(255),
  `iniciado` TINYINT(1),
  `c_2a_fase_testes_volumetria` VARCHAR(255),
  `resultado` VARCHAR(255),
  `clientes_utilizam_funcionalidade` VARCHAR(50),
  `nome_da_regra` VARCHAR(100),
  `configuracao_da_regra` VARCHAR(200),
  `executor_da_regra` VARCHAR(50),
  `tipo_de_regra` VARCHAR(50),
  `protocolo_parceiro` VARCHAR(50),
  `resultado_esperado` VARCHAR(200),
  `detalhamento_da_execucao_do_teste` TEXT,
  `resultado_obtido_com_1_arquivo_simples` VARCHAR(50),
  `resultado_obtido_com_1_arquivo_1gb` VARCHAR(50),
  `resultado_obtido_com_100_arquivos` VARCHAR(50),
  `resultado_obtido_com_5000_arquivos` VARCHAR(50),
  `versao_do_edie` VARCHAR(50),
  `build` INT,
  `issue` VARCHAR(50),
  `criticidade_issue` VARCHAR(50),
  `observacoes` TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `regras_reprovadas`;
CREATE TABLE `regras_reprovadas` (
  `id_pk` INT AUTO_INCREMENT PRIMARY KEY,
  `localizacao` VARCHAR(255),
  `id` VARCHAR(255),
  `nome_da_regra` VARCHAR(255),
  `resultado` VARCHAR(255),
  `criticidade` VARCHAR(255)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `listas`;
CREATE TABLE `listas` (
  `id_pk` INT AUTO_INCREMENT PRIMARY KEY,
  `resultado` VARCHAR(50),
  `tipo_de_regra` VARCHAR(50),
  `protocolo` VARCHAR(50),
  `resultado_esperado` VARCHAR(50),
  `criticidade` VARCHAR(50),
  `clientes` VARCHAR(50),
  `profissionais` VARCHAR(50),
  `executor` VARCHAR(50),
  `versao_edie` VARCHAR(50)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `engine`;
CREATE TABLE `engine` (
  `id_pk` INT AUTO_INCREMENT PRIMARY KEY,
  `origem` VARCHAR(50),
  `id` INT,
  `nome` VARCHAR(100),
  `resultado` VARCHAR(255),
  `criticidade` VARCHAR(50),
  `flag` INT,
  `matchno` VARCHAR(255)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


SET FOREIGN_KEY_CHECKS = 1;